/**
 * A logging output channel, console/syslog/file
 * @name Output
 * @type enum
 * @prop console 'console'
 * @prop syslog 'syslog'
 * @prop file 'file'
 */
declare type Output = 'console' | 'syslog' | 'file';
declare namespace Output {
    const console: Output;
    const syslog: Output;
    const file: Output;
}
export default Output;
